const events = $input.all();
const interviewEvents = [];

for (const event of events) {
  const e = event.json || {};
  const summary = (event.json.summary || '').toLowerCase();
  const desc = (event.json.description || '').toLowerCase();

  // try extendedProperties first
  let candidatePhone = e.extendedProperties?.private?.candidate_phone || null;

  // fallback to "Candidate Phone: +92..."
  if (!candidatePhone && e.description) {
    const m = e.description.match(/candidate\s*phone[:\-]?\s*([+\d\s\-().]{6,})/i);
    if (m) candidatePhone = m[1].trim();
  }

  // normalize simple
  const normalize = (num) => {
    if (!num) return '';
    num = num.replace(/[\s-]/g, '');
    if (num.startsWith('+92')) return num;
    if (num.startsWith('0')) return '+92' + num.slice(1);
    if (num.startsWith('92')) return '+' + num;
    return num;
  };
  candidatePhone = normalize(candidatePhone);

  // basic e164-ish check
  const validPhone = /^\+[1-9]\d{7,14}$/.test(candidatePhone);

  const isInterview =
    summary.includes('interview') ||
    desc.includes('interview') ||
    summary.includes('screening') ||
    summary.includes('candidate') ||
    summary.includes('call with');

  const isPersonal =
    summary.includes('dinner') ||
    summary.includes('lunch') ||
    summary.includes('personal') ||
    summary.includes('doctor') ||
    summary.includes('family') ||
    summary.includes('gym');

  if (isInterview && !isPersonal && validPhone) {
    interviewEvents.push({ ...e, candidatePhone });
  }
}

return interviewEvents.map(item => ({ json: item }));

const now = new Date();
const out = [];

for (const { json:e } of $input.all()) {
  // supports both start.dateTime or start.date
  const raw = e?.start?.dateTime || e?.start?.date;
  if (!raw) continue;

  const start = new Date(raw);
  const diffMin = (start - now) / 60000;

  const in1h = diffMin >= 53  && diffMin <= 67;   // 1h  ±7m
  const in4h = diffMin >= 233 && diffMin <= 247;  // 4h  ±7m


  if (!in4h && !in1h) continue;

  out.push({
    json: {
      ...e,
      reminderType: in4h ? '4_hour' : '1_hour',
      diffMin
    }
  });
}

return out;

const ev = $json;

// ---- Candidate name: after the last " - " in summary ----
let candidateName = 'Candidate';
if (ev.summary) {
  const parts = ev.summary.split('-');
  candidateName = (parts[parts.length - 1] || '').trim() || 'Candidate';
}

// ---- Position (fallbacks safe) ----
const position =
  ev.description?.match(/Position:\s*([^\n<]+)/i)?.[1]?.trim() ||
  (ev.summary?.replace(/[-–].*$/, '').replace(/Interview/i, '').trim() || 'Interview');

// ---- Pick ONE meeting link only (dedupe + preference) ----
const desc = ev.description || '';
const urlRegex = /(https?:\/\/[^\s<>"')]+)/g;
const fromDesc = desc.match(urlRegex) || [];
const candidates = [ev.hangoutLink, ...fromDesc].filter(Boolean);

// unique list
const unique = [...new Set(candidates)];

// preference order
const meetingLink =
  unique.find(u => u.includes('meet.google.com')) ||
  unique.find(u => u.includes('zoom.us')) ||
  unique.find(u => u.includes('teams.microsoft.com')) ||
  unique[0] || '';

// ---- Times formatted in PKT (or event TZ if set) ----
const eventTime = new Date(ev.start_time || ev.start?.dateTime || ev.date);
const timeZone = ev.start?.timeZone || 'Asia/Karachi';

const timeStr = eventTime.toLocaleTimeString('en-US', { 
  timeZone, 
  hour: 'numeric', 
  minute: '2-digit', 
  hour12: true 
});

const dateStr = eventTime.toLocaleDateString('en-GB', { 
  timeZone, 
  day: 'numeric', 
  month: 'short', 
  year: 'numeric' 
});

// ---- Reminder timeframe ----
let timeframe = '';
if (ev.reminder_type === '4_hour') timeframe = '4 hours';
else if (ev.reminder_type === '1_hour') timeframe = '1 hour';
else timeframe = ''; // fallback

// ---- Phone ----
const candidatePhone =
  ev.phone ||
  ev.extendedProperties?.private?.phone ||
  '';

// ---- Organizer name ----
const orgName = ev.organizer?.displayName || 'HR Team';
//
const interviewer =
  ev.description?.match(/Interviewer:\s*([^\n<]+)/i)?.[1]?.trim() || '';

// ---- Return all fields separately ----
return {
  candidateName,
  timeframe,
  date: dateStr,
  time: timeStr,
  position,
  meetingLink,
  candidatePhone,
  eventId: ev.id,
  reminder_type: ev.reminder_type,
  orgName,
  interviewer
};

const body = $json.body || $json;

// Default fields
let phone = null;
let text = null;
let action = "unknown";
let messageId = null;

// --- Handle inbound messages ---
const msg = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
if (msg) {
  phone = msg.from;
  text = msg.text?.body || null;
  messageId = msg.id;

  if (text) {
    const lower = text.toLowerCase();
    if (lower.includes("confirm")) action = "confirm";
    else if (lower.includes("reschedule")) action = "reschedule";
    else if (lower.includes("cancel")) action = "cancel";
  }
}

// --- Handle status updates ---
const status = body.entry?.[0]?.changes?.[0]?.value?.statuses?.[0];
if (status) {
  phone = status.recipient_id;
  text = status.status; // e.g. "sent", "delivered", "read", "failed"
  messageId = status.id;
  action = "status";
}

return [
  {
    json: {
      phone,
      text,
      action,
      messageId
    }
  }
];
